private RealMatrix squareRoot(RealMatrix m) {
    if (!(m instanceof org.apache.commons.math3.linear.DiagonalMatrix)) {
        throw new IllegalArgumentException("Matrix should be a DiagonalMatrix");
    }
    double[] diagonal = ((org.apache.commons.math3.linear.DiagonalMatrix) m).getDataRef();
    double[] sqrtDiagonal = new double[diagonal.length];
    for (int i = 0; i < diagonal.length; i++) {
        sqrtDiagonal[i] = Math.sqrt(diagonal[i]);
    }
    return new org.apache.commons.math3.linear.DiagonalMatrix(sqrtDiagonal);
}
